INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('real-estate-moex-01522', 'real-estate', 'real-estate-moex-104-9a386a01', 'sub-real-estate-06', NULL, 'single_choice', '在生活裏，一切都好像是正常和必須的，所以我們一切的反應也都是從容和有規有 矩的。但是，在面對着只屬於生命的那些獨特時刻裏，卻總會有一種壓力迎面而來， 讓我們覺得猶疑、戰慄和身不由己。 十九歲那年，站在山坡上，遠遠望去，彷彿所有的峯巒、所有的江流都充滿了一種 令人振奮的希望。而二十年後再來登臨，再來遠遠地望過去，山巒與江流外面的世 界就是我們曾經摸索追尋、跌倒再爬起來、哭過也笑過的那一個世界。在灰紫色的 暮靄裏，所有的過去井然有序地在我眼前排列開來，我發現，我竟然能夠很輕易地 就分辨了出來，那些時刻是屬於生活，而那些時刻是只屬於我的生命的了。 因此，就真的好像我寫的那兩句詩了： －－所有的時刻都很倉惶而又模糊 除非你能停下來  遠遠地回顧  （席慕蓉〈兩種時刻〉） 下列敘述何者最貼近本文意旨？', '["回首來時路，一切了然於心", "坐看雲起時，一切盡付笑談中", "船過水無痕，過去的就別計較了", "人生如朝露，活在當下及時行樂"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:09+00:00", "source_pdf_sha1": "55650f2180a5", "answer_pdf_sha1": "d5d38050b082", "source_family": "moex-gov-tw", "moex": {"exam_code": "104170", "c": "601", "s": "1301", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "104", "exam_name": "104年專技建築師、技師、第二次食品技師、不動產經紀人、記帳士考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01523', 'real-estate', 'real-estate-moex-104-9a386a01', 'sub-real-estate-06', NULL, 'single_choice', '「天生萬物，有美有不美，有才有不才。萬具枯骨，才造得一員名將；小兵小卒， 豈能都成為有名的英雄？世上有坐轎的，有抬轎的；有坐席的主人和賓客，有端茶 上菜的侍僕。」 本文旨在說明：', '["天生我才必有用", "職業無貴賤，行行出狀元", "天之生材不齊，無法一律均等", "一人的成功往往建立在眾人的付出之上"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:09+00:00", "source_pdf_sha1": "55650f2180a5", "answer_pdf_sha1": "d5d38050b082", "source_family": "moex-gov-tw", "moex": {"exam_code": "104170", "c": "601", "s": "1301", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "104", "exam_name": "104年專技建築師、技師、第二次食品技師、不動產經紀人、記帳士考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01524', 'real-estate', 'real-estate-moex-104-9a386a01', 'sub-real-estate-06', NULL, 'single_choice', '華歆、王朗俱乘船避難，有一人欲依附，歆輒難之。朗曰：「幸尚寬，何為不可？」 後賊追至，王欲捨所攜人。歆曰：「本所以疑，正為此耳。既已納其自託，寧可以 急相棄邪？」遂攜拯如初。世以此定華、王之優劣。（《世說新語．德性》） 下列選項何者最近於華歆助人之道？', '["勿為德不卒", "飲水不忘挖井人", "人人為我，我為人人", "病人之病，憂人之憂"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:09+00:00", "source_pdf_sha1": "55650f2180a5", "answer_pdf_sha1": "d5d38050b082", "source_family": "moex-gov-tw", "moex": {"exam_code": "104170", "c": "601", "s": "1301", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "104", "exam_name": "104年專技建築師、技師、第二次食品技師、不動產經紀人、記帳士考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01525', 'real-estate', 'real-estate-moex-104-9a386a01', 'sub-real-estate-06', NULL, 'single_choice', '「且夫水之積也不厚，則其負大舟也無力。覆杯水於坳堂之上，則芥為之舟；置杯焉 則膠，水淺而舟大也。風之積也不厚，則其負大翼也無力。」（《莊子‧逍遙遊》） 本段意指：', '["積少成多方能致富", "積重難返徒勞無功", "積累實力乃能成就大事", "積極向上始克有所作為 60210"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:09+00:00", "source_pdf_sha1": "55650f2180a5", "answer_pdf_sha1": "d5d38050b082", "source_family": "moex-gov-tw", "moex": {"exam_code": "104170", "c": "601", "s": "1301", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "104", "exam_name": "104年專技建築師、技師、第二次食品技師、不動產經紀人、記帳士考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01526', 'real-estate', 'real-estate-moex-104-9a386a01', 'sub-real-estate-06', NULL, 'single_choice', '「決定海岸管理方式時，讓在地社區扮演舉足輕重的角色是很重要的。」莫里斯強 調。該組織贏得廣大英國人民支持與信任的原因之一，就在於積極邀請民眾參與。 海神計畫不做黑箱作業，而是主動「和在地社區一起深入探討各種方案、檢視證據、 確立問題的解決之道，幫助他們了解和適應海岸面臨的變化。」 而且，不管立意如何良善、設計如何精良，英國國民信託堅持不能強迫居民接受任 何方案，而是兼具感性與想像力，長時間與居民溝通對話，達成共識，互相學習。 「重點是，我們不能高高在上地自以為是，而是要讓民眾感受到他們的意見是被聆 聽與重視的，就算我們不盡然同意他們的看法。」莫里斯提醒。 一開始，國民信託會與當地社區討論，一起確立當地獨特的重要性，並徵詢遊客的 意見，達成共識。而這份共識不僅將成為未來經營管理的有用依據，也是將居民納 入國民信託計畫的陣營，共同為環境努力。（賴慧玲〈英國國民信託啟示：給自己 一個改變現況的機會〉） 依上文，有關英國國民信託的敘述，下列選項何者正確？', '["莫里斯分享海神計畫中有關海岸管理方式的經驗", "國民信託會邀請當地居民對談，從未有過不同意見", "國民信託會以專家建議為主，輔以在地社區居民的意見", "英國國民信託能獲得民眾的支持，主因在於立意良善、設計精良"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:09+00:00", "source_pdf_sha1": "55650f2180a5", "answer_pdf_sha1": "d5d38050b082", "source_family": "moex-gov-tw", "moex": {"exam_code": "104170", "c": "601", "s": "1301", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "104", "exam_name": "104年專技建築師、技師、第二次食品技師、不動產經紀人、記帳士考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01527', 'real-estate', 'real-estate-moex-104-9a386a01', 'sub-real-estate-06', NULL, 'single_choice', '新生南路這條路（此為瑠公圳最大幹道，它如安東街、延吉街等，亦是瑠公圳眾多 支渠中之要者），若我今日想來，是昔年臺北最重要、最素美的市內河景，亦是我 臺北孩子不自禁生負某種自卑感之下卻猶能以之緬懷而深感尊嚴的一處地標。它未 必被視為古蹟；若林安泰古厝之拆遷、理教總公所（西本願寺）之毀於火焚、新生 報舊址之改建、公賣局木造樓舍及臺大醫學院木造樓舍之拆除……，固極可惜，也 還罷了，然這城市之內一泓天成溪流，南北迆邐好幾公里，河上樹影，春花秋月， 實臺北市即使趨奔現代，也不宜改觀這一抹與「現代」毫不相悖的活水氣質。一九 七二年之覆蓋填掩，固為臺北多占了幾畝陸地，卻令臺北意欲晉身世界大都會原本 極可羨人，並又生死攸關的一條天生麗質血管就這麼斷然結紮了。（舒國治〈水城 臺北〉） 舒國治描述水道與人生活的關聯，一九七二年覆蓋填掩瑠公圳的行為無異「結紮」 一語，乃在強調水道之於城市人生活間具備何種意義：', '["反應人生時間的無情流逝", "涵攝生命源頭與流動活力", "提供放鬆心神與休閒遊憩", "鼓勵投入勞動與後代繁衍"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:09+00:00", "source_pdf_sha1": "55650f2180a5", "answer_pdf_sha1": "d5d38050b082", "source_family": "moex-gov-tw", "moex": {"exam_code": "104170", "c": "601", "s": "1301", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "104", "exam_name": "104年專技建築師、技師、第二次食品技師、不動產經紀人、記帳士考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01528', 'real-estate', 'real-estate-moex-104-9a386a01', 'sub-real-estate-06', NULL, 'single_choice', '時髦與美沒有必然的關係，它與習慣有關係。人類對事物的愛好是從新奇開始，然 後是熟習，最後是麻木。當熟習一種造型的時候，產生感情上水乳交融的關係，並 未考慮到美醜。可是並非與美感毫無關係。舉例說，今天的年輕人喜歡把頭髮染成 棕色，這是自日本傳來的一種流行。年輕人開始是好奇，久而久之，竟覺得頭髮不 染就過於老派，因此大家都染，已經很習慣了。可是我們年紀大的人看他們染髮也 許看不慣，身為旁觀者，卻看得出有的頭髮染得恰如其分，有些染得過分，因此失 了美感。如果冷靜下來，即使在時尚中，仍然可以辨別美醜。因為美的一些基本原 則仍然是可以通用的。這就是說，時髦本身與美無關，但它仍然要受到美的批判。 只是在流行之中，人的美感反應受到麻醉，常常忽略了客觀的美感判斷。所以對我 而言，時髦是美感的麻醉劑，是應該非常注意的，雖然不能避免卻不可沉迷其中。 （漢寶德〈時髦與美感〉） 根據上文，下列選項何者錯誤？', '["時髦與美感沒有任何關係", "時髦是一種流行，代表時尚", "時髦與習慣具有密切的關係", "時髦麻醉美感，容易失去美感判斷 60210"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:09+00:00", "source_pdf_sha1": "55650f2180a5", "answer_pdf_sha1": "d5d38050b082", "source_family": "moex-gov-tw", "moex": {"exam_code": "104170", "c": "601", "s": "1301", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "104", "exam_name": "104年專技建築師、技師、第二次食品技師、不動產經紀人、記帳士考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01529', 'real-estate', 'real-estate-moex-104-9a386a01', 'sub-real-estate-06', NULL, 'single_choice', '請閱讀下列兩段文字，選擇對此兩段文字內容、意旨最正確的詮釋： 宋人或得玉，獻諸司城子罕，子罕不受。獻玉者曰：「以示玉人，玉人以為寶，故 敢獻之。」子罕曰：「我以不貪為寶，爾以玉為寶，若以與我，皆喪寶也。不若人 有其寶。」 公儀休為魯相，……客有遺相魚者，相不受。客曰：「聞君嗜魚，故遺君魚，何故 不受？」公儀休曰：「以嗜魚，故不受也。今為相，能自給魚。今受魚而免相，誰 復給我魚者？吾故不受也。」', '["子罕與公儀休重操守而不接受饋贈", "子罕能實踐「己所不欲，勿施於人」", "公儀休不接受贈魚，乃因「由奢入儉」難", "子罕能推己及人，不願奪人所愛，不忍他人喪其寶"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:09+00:00", "source_pdf_sha1": "55650f2180a5", "answer_pdf_sha1": "d5d38050b082", "source_family": "moex-gov-tw", "moex": {"exam_code": "104170", "c": "601", "s": "1301", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "104", "exam_name": "104年專技建築師、技師、第二次食品技師、不動產經紀人、記帳士考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01530', 'real-estate', 'real-estate-moex-104-9a386a01', 'sub-real-estate-06', NULL, 'single_choice', '「《莊子‧秋水篇》寫道：『井蛙不可以語於海者，拘於墟也。夏蟲不可以語於冰 者，篤於時也。曲士不可以語於道者，束於教也。』拘於墟是為□□所限，篤於時 是為□□所限，束於教是被□□所限。」（陳冠學〈對稱〉） 本文中□□，依序應為：', '["生命／環境／宗教", "視野／境界／思想", "時間／空間／信仰", "空間／時間／教條"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:09+00:00", "source_pdf_sha1": "55650f2180a5", "answer_pdf_sha1": "d5d38050b082", "source_family": "moex-gov-tw", "moex": {"exam_code": "104170", "c": "601", "s": "1301", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "104", "exam_name": "104年專技建築師、技師、第二次食品技師、不動產經紀人、記帳士考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01531', 'real-estate', 'real-estate-moex-104-9a386a01', 'sub-real-estate-06', NULL, 'single_choice', '「隋趙車丸為齊州別駕。東鄰有桑葚落其家，車丸悉拾還其主。……及詔入朝，父老揮 涕曰：『別駕在官，水火不與百姓交，不敢以盃酒相送。公清如水，請酌一盃水奉 餞。』車丸受飲之。後為原州司馬，在道夜行，馬逸入田中，暴人禾。車丸駐馬待明， 訪知禾主，酬直而去。」（王罃《群書類編故事》） 由此足見趙車丸：', '["吹毛求疵，事事計較", "清廉正直，不欺暗室", "處事謹慎，公而忘私", "不貪小錢，私受大錢"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:09+00:00", "source_pdf_sha1": "55650f2180a5", "answer_pdf_sha1": "d5d38050b082", "source_family": "moex-gov-tw", "moex": {"exam_code": "104170", "c": "601", "s": "1301", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "104", "exam_name": "104年專技建築師、技師、第二次食品技師、不動產經紀人、記帳士考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL)
